interface BrightnessFilterProps {
  /** The id of the filter, to be used in the SVG element that will be styled, using the filter prop. Example: <g filter="url(#myFilterId)"></g> */
  id: string;
  /** The "slope" of the linear function of the color. Use this POC to find the equivalent to CSS filter prop: https://codepen.io/xavi-ortega/pen/jOvdRpw */
  slope: number;
}

/**
 * SVG brightness filter component.
 *
 * CSS filter property doesn't work properly with SVG in Safari, so we use the SVG native filter to apply brightness effect.
 *
 * Note: if there's any weird behavior with the filter, check this PR comment: https://bitbucket.lab.dynatrace.org/projects/APPFW/repos/design-system/pull-requests/6140/overview?commentId=1067402
 */
export const BrightnessFilter = ({ id, slope }: BrightnessFilterProps) => (
  <filter id={id} filterUnits="userSpaceOnUse">
    <feComponentTransfer>
      <feFuncR type="linear" slope={slope} />
      <feFuncG type="linear" slope={slope} />
      <feFuncB type="linear" slope={slope} />
    </feComponentTransfer>
  </filter>
);
